SELECT a.id, a.title, a.summary, a.cover_image, a.status, a.visible, a.publish_time, a.last_edit_time, a.read_count, a.like_count, a.comment_count, a.user_id, a.author_name, a.category_id, u.avatar, c.name as category_name FROM article a LEFT JOIN category c ON a.category_id = c.id LEFT JOIN user u ON a.user_id = u.id WHERE a.deleted = 0
AND a.category_id = #{query.categoryId}
AND (a.title LIKE CONCAT('%', #{query.keyword}, '%') OR a.summary LIKE CONCAT('%', #{query.keyword}, '%'))
GROUP BY a.id ORDER BY a.top DESC, a.recommended DESC LIMIT #{query.offset}, #{query.pageSize}

